/** Look up a regional page by slug */
export function getRegionalPageBySlug(slug: string): RegionalPageData | undefined {
  return regionalPages.find((p) => p.slug === slug);
}

/** Get all regional page slugs for static params */
export function getAllRegionalSlugs(): string[] {
  return regionalPages.map((p) => p.slug);
}
